#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <iostream>
#include <cstring>
#include <omp.h>

using namespace std;

#define HALO     1
#define STR_SIZE 256
#define DEVICE   0
#define M_SEED   9

#define IN_RANGE(x, min, max)	((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

int   rows = -1, cols = -1;
int   Ne = rows * cols;
int*  data;
int** wall;
int*  result;
int   pyramid_height = -1;
int   verbose = 0;

void init(int argc, char** argv)
{
    int cur_arg;
	for (cur_arg = 1; cur_arg<argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-c") == 0) {
            if (argc >= cur_arg + 1) {
                cols = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-r") == 0) {
            if (argc >= cur_arg + 1) {
                rows = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-h") == 0) {
            if (argc >= cur_arg + 1) {
                pyramid_height = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        if (strcmp(argv[cur_arg], "-v") == 0) {
			verbose = 1;
        }
    }

	if (cols < 0 || rows < 0 || pyramid_height < 0)
	{
        fprintf(stderr, "usage: %s <-r rows> <-c cols> <-h pyramid_height> [-v]\n", argv[0]);
		exit(0);
	}
	data = new int[rows * cols];
	wall = new int*[rows];
	for (int n = 0; n < rows; n++)
	{
		wall[n] = data + cols * n;
	}
	result = new int[cols];

	int seed = M_SEED;
	srand(seed);

	for (int i = 0; i < rows; i++)
	{
		for (int j = 0; j < cols; j++)
		{
			wall[i][j] = rand() % 10;
		}
	}
}

void dynproc_kernel(int iteration,
                    int* gpuWall,
                    int* gpuSrc,
                    int* gpuResults,
                    int cols,
                    int rows,
                    int startStep,
                    int border,
                    int HALO,
                    int BLOCK_SIZE,
                    int bx,
                    int* outputBuffer)
{
	int small_block_cols = BLOCK_SIZE - (iteration*HALO*2);

	int blkX = (small_block_cols*bx) - border;
	int blkXmax = blkX+BLOCK_SIZE-1;

	int* prev = new int[BLOCK_SIZE];
	int* result = new int[BLOCK_SIZE];

	int validXmin = (blkX < 0) ? -blkX : 0;
	int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

	for (int tx = 0; tx < BLOCK_SIZE; tx++)
	{
		int xidx = blkX + tx;
		bool isValid = IN_RANGE(tx, validXmin, validXmax);

		int W = tx-1;
		int E = tx+1;

		W = (W < validXmin) ? validXmin : W;
		E = (E > validXmax) ? validXmax : E;

		if (IN_RANGE(xidx, 0, cols-1))
		{
			prev[tx] = gpuSrc[xidx];
		}
		else
		{
			prev[tx] = 0;
		}
	}

	for (int i = 0; i < iteration; i++)
	{
		for (int tx = 0; tx < BLOCK_SIZE; tx++)
		{
			bool computed = false;
			int xidx = blkX + tx;
			bool isValid = IN_RANGE(tx, validXmin, validXmax);
			if (IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid)
			{
				computed = true;
				int left = prev[(tx-1 < validXmin) ? validXmin : tx-1];
				int up = prev[tx];
				int right = prev[(tx+1 > validXmax) ? validXmax : tx+1];
				int shortest = MIN(left, up);
				shortest = MIN(shortest, right);

				int index = cols*(startStep+i)+xidx;
				result[tx] = shortest + gpuWall[index];

				if (tx==11 && i==0)
				{
					int bufIndex = gpuSrc[xidx];
					outputBuffer[bufIndex] = 1;
				}
			}
			else
			{
				result[tx] = prev[tx];
			}
		}
		if (i == iteration - 1)
		{
			break;
		}
		for (int tx = 0; tx < BLOCK_SIZE; tx++)
		{
			bool computed = IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && IN_RANGE(blkX+tx, 0, cols-1) && IN_RANGE(tx, validXmin, validXmax);
			if (computed)
			{
				prev[tx] = result[tx];
			}
		}
	}

	for (int tx = 0; tx < BLOCK_SIZE; tx++)
	{
		bool computed = IN_RANGE(tx, iteration, BLOCK_SIZE-iteration-1) && IN_RANGE(blkX+tx, 0, cols-1) && IN_RANGE(tx, validXmin, validXmax);
		if (computed)
		{
			int xidx = blkX + tx;
			gpuResults[xidx] = result[tx];
		}
	}

	delete[] prev;
	delete[] result;
}

int main(int argc, char** argv)
{
	init(argc, argv);

	int borderCols = (pyramid_height) * HALO;

	int size = rows * cols;

	int* d_gpuWall = new int[size - cols];
	memcpy(d_gpuWall, data + cols, sizeof(int) * (size - cols));

	int* d_gpuResult[2];
	d_gpuResult[0] = new int[cols];
	d_gpuResult[1] = new int[cols];
	memcpy(d_gpuResult[0], data, sizeof(int) * cols);

	int* h_outputBuffer = new int[16384];
	memset(h_outputBuffer, 0, sizeof(int) * 16384);

	int src = 1, final_ret = 0;
	int BLOCK_SIZE = cols;

	for (int t = 0; t < rows - 1; t += pyramid_height)
	{
		int temp = src;
		src = final_ret;
		final_ret = temp;

		int arg0 = MIN(pyramid_height, rows - t - 1);
		int theHalo = HALO;

		// Parallel launch of dynproc_kernel equivalent with OpenMP over blocks
		int small_block_cols = BLOCK_SIZE - (arg0 * theHalo * 2);
		int num_blocks = (cols + small_block_cols - 1) / small_block_cols;

#pragma omp parallel for schedule(static)
		for (int bx = 0; bx < num_blocks; bx++)
		{
			dynproc_kernel(arg0,
			               d_gpuWall,
			               d_gpuResult[src],
			               d_gpuResult[final_ret],
			               cols,
			               rows,
			               t,
			               borderCols,
			               theHalo,
			               BLOCK_SIZE,
			               bx,
			               h_outputBuffer);
		}
	}

	memcpy(result, d_gpuResult[final_ret], sizeof(int) * cols);

	h_outputBuffer[16383] = '\0';

#ifdef BENCH_PRINT
	for (int i = 0; i < cols; i++)
		printf("%d ", data[i]);
	printf("\n");
	for (int i = 0; i < cols; i++)
		printf("%d ", result[i]);
	printf("\n");
#endif

	delete[] d_gpuWall;
	delete[] d_gpuResult[0];
	delete[] d_gpuResult[1];
	delete[] h_outputBuffer;
	delete[] data;
	delete[] wall;
	delete[] result;

	return EXIT_SUCCESS;
}
